/// <summary>
/// Provides access to an instrumentation logger.
/// </summary>
/// <returns>
/// The <c>WMHEInstrumentationLogger</c> object.
/// </returns>
internal final KPMGCommon_WMHEInstrumentationLogger KPMGCommon_instrumentationLogger()
{
    if (!kPMGCommon_instrumentationLogger)
    {
        kPMGCommon_instrumentationLogger = KPMGCommon_WMHEInstrumentationLogger::createLogger(classId2Name(classIdGet(this)));
    }

    return kPMGCommon_instrumentationLogger;
}
